import { Metadata } from 'next';
import HeroAreaOne from '@/components/hero-area/hero-area-one';
import AboutOne from '@/components/about/about-one';
import CounterOne from '@/components/counter/counter-one';
import ProgramArea from '@/components/program/program-area';
import CtaOne from '@/components/cta/cta-one';
import { schoolData } from '@/data/schoolData';
import Link from 'next/link';

export const metadata: Metadata = {
  title: "Home - Sree Jayam School",
  description: "Learn to Live - Sree Jayam School, Vellore. ICSE & ISC Affiliated.",
};

export default function HomePage() {
  const { results } = schoolData;
  
  return (
    <main>
      {/* hero area start */}
      <HeroAreaOne/>
      {/* hero area end */}

      {/* about area start */}
      <AboutOne/>
      {/* about area end */}

      {/* counter area start */}
      <CounterOne/>
      {/* counter area end */}

      {/* program area start (Academic Stages) */}
      <ProgramArea/>
      {/* program area end */}

      {/* Results Highlight Section */}
      <section className="results-area pt-100 pb-100 grey-bg">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-lg-8">
              <div className="tp-section text-center mb-60">
                <h3 className="tp-section-title">Academic Results</h3>
                <p>Consistently achieving excellence year after year.</p>
              </div>
            </div>
          </div>
          <div className="row justify-content-center">
            <div className="col-lg-10">
              <div className="table-responsive">
                <table className="table table-bordered text-center" style={{ backgroundColor: 'white' }}>
                  <thead style={{ backgroundColor: '#1A3C6E', color: 'white' }}>
                    <tr>
                      <th>Class</th>
                      <th>Year</th>
                      <th>Pass %</th>
                    </tr>
                  </thead>
                  <tbody>
                    {results.map((item, index) => (
                      <tr key={index}>
                        <td>{item.class}</td>
                        <td>{item.year}</td>
                        <td style={{ fontWeight: 'bold', color: '#1A3C6E' }}>{item.passPercentage}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Why Choose Us Teaser */}
      <section className="why-teaser pt-100 pb-100">
        <div className="container">
          <div className="row align-items-center">
            <div className="col-lg-6">
              <div className="tp-section mb-40">
                <h3 className="tp-section-title">Why Choose Us?</h3>
                <p>We provide a safe, caring and child-friendly atmosphere with an emphasis on social, emotional and basic skill development.</p>
              </div>
              <ul className="mb-40" style={{ listStyle: 'none', padding: 0 }}>
                <li className="mb-10">✔ Activity-based learning to build confidence</li>
                <li className="mb-10">✔ Safe and supportive environment</li>
                <li className="mb-10">✔ Qualified and dedicated teachers</li>
              </ul>
              <Link href="/why-choose-us" className="tp-btn">Learn More</Link>
            </div>
            <div className="col-lg-6">
                     <div style={{ backgroundColor: '#f1f1f1', height: '400px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyItems: 'center' }}>
                        <p style={{ margin: 'auto' }}>[REPLACE_WITH_SCHOOL_IMAGE]</p>
                     </div>
            </div>
          </div>
        </div>
      </section>

      {/* cta area start */}
      <CtaOne/>
      {/* cta area end */}
    </main>
  )
}
